CREATE DATABASE IF NOT EXISTS football DEFAULT CHARACTER SET utf8mb4;
USE football;
DROP TABLE IF EXISTS 最终世界杯前锋报告;
CREATE TABLE 最终世界杯前锋报告 (
  player_id BIGINT,
  name TEXT,
  nationality_cn TEXT,
  squad_nation TEXT,
  team_name TEXT,
  league_name TEXT,
  position_category TEXT,
  assigned_role TEXT,
  战术角色中文 TEXT,
  age BIGINT,
  goal BIGINT,
  assist_total BIGINT,
  xg DOUBLE,
  key_pass_per_game DOUBLE,
  dribble_won_per_game DOUBLE,
  shots_per_game DOUBLE,
  total_passes_per_game DOUBLE,
  shooting_efficiency DOUBLE,
  touches_adjusted_lethality DOUBLE,
  market_value_eur DOUBLE,
  AI_True_Value DOUBLE,
  Value_Exploitation_Index DOUBLE,
  Apex_Role_Scout_Score DOUBLE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

